#include<bits/stdc++.h>
using namespace std;
long long f[2000010];
int main()
{
    int n;
    scanf("%d",&n);
    long long ans=0;
    for(int i=n;i>=1;i--)
    {
        f[i]=1ll*(n/i)*(n/i);
        for(int j=i*2;j<=n;j+=i)
        {
            f[i]-=f[j];
        }
        ans+=f[i]*i;
    }
    printf("%lld",ans);
    return 0;
}
